// Unit test for computeBestWindow — verifies it picks the calmest 3-hour block
// (lowest combined wind + gust) from a crafted hourly array, with correct
// averages, score, hour count, and a descriptive reason string.
async function testComputeBestWindow() {
  // Build an hourly array of 8 hours. Indices 3,4,5 are clearly the calmest:
  // wind 4/5/6 (avg 5), gusts 6/7/8 (avg 7) -> combinedScore 12.
  // Every other 3-hour block has a higher combined wind+gust.
  const hourly = [
    { time: '2026-06-26T00:00', windSpeed: 20, windGusts: 28 },
    { time: '2026-06-26T01:00', windSpeed: 18, windGusts: 25 },
    { time: '2026-06-26T02:00', windSpeed: 16, windGusts: 22 },
    { time: '2026-06-26T03:00', windSpeed: 4,  windGusts: 6 },
    { time: '2026-06-26T04:00', windSpeed: 5,  windGusts: 7 },
    { time: '2026-06-26T05:00', windSpeed: 6,  windGusts: 8 },
    { time: '2026-06-26T06:00', windSpeed: 14, windGusts: 19 },
    { time: '2026-06-26T07:00', windSpeed: 17, windGusts: 23 }
  ];

  const window = functions.call('computeBestWindow', hourly, 3, 24);

  // A window should be found
  assert(window !== null, 'computeBestWindow should return a window');

  // The calmest block starts at index 3
  assertEquals(window.startIndex, 3, 'Calmest window should start at index 3');
  assertEquals(window.start, 3, 'start should match startIndex');
  assertEquals(window.end, 5, 'end should be start + windowHours - 1');

  // Averages: wind (4+5+6)/3 = 5, gust (6+7+8)/3 = 7, combined = 12
  assertEquals(window.avgWind, 5, 'avgWind should be 5 kn');
  assertEquals(window.avgGust, 7, 'avgGust should be 7 kn');
  assertEquals(window.combinedScore, 12, 'combinedScore should be avgWind + avgGust');

  // Exactly 3 hours in the window, in order
  assertEquals(window.hours.length, 3, 'Window should contain exactly 3 hours');
  assertEquals(window.hours[0].time, '2026-06-26T03:00', 'First hour time should match');
  assertEquals(window.startTime, '2026-06-26T03:00', 'startTime should be the first hour');
  assertEquals(window.endTime, '2026-06-26T05:00', 'endTime should be the last hour');

  // Reason string should be present and mention the start time
  assert(typeof window.reason === 'string' && window.reason.length > 0, 'reason should be a non-empty string');
  assert(window.reason.indexOf('03:00') >= 0, 'reason should mention the window start time');

  // Edge case: fewer hours than the window size returns null
  const tooShort = functions.call('computeBestWindow', hourly.slice(0, 2), 3, 24);
  assertEquals(tooShort, null, 'Should return null when not enough hours for one window');
}
